function copyRandomListBruteForce(head: RandomListNode | null): RandomListNode | null {
  if (!head) {
    return null
  }

  const originalNodes: RandomListNode[] = []
  let currentOriginalNode: RandomListNode | null = head

  // Step 1-3: Create new nodes with the same values as the original list
  while (currentOriginalNode) {
    const copyNode = new RandomListNode(currentOriginalNode.val)
    originalNodes.push(copyNode)
    currentOriginalNode = currentOriginalNode.next
  }

  // Link the copied nodes together to form the copied linked list
  for (let i = 0; i < originalNodes.length - 1; i++) {
    originalNodes[i].next = originalNodes[i + 1]
  }

  const copiedHead: RandomListNode = originalNodes[0]

  currentOriginalNode = head
  let currentCopyNode: RandomListNode | null = copiedHead

  // Step 4-6: Match random pointers
  while (currentOriginalNode) {
    const originalRandom: RandomListNode | null = currentOriginalNode.random

    if (originalRandom) {
      // Find the index of the original random node
      let randomIndex = 0
      let tempNode: RandomListNode | null = head
      while (tempNode !== originalRandom) {
        tempNode = tempNode.next
        randomIndex++
