      // Set the random pointer of the copy node to the corresponding copy node
      currentCopyNode.random = originalNodes[randomIndex]
    } else {
      currentCopyNode.random = null
    }

    currentOriginalNode = currentOriginalNode.next
    currentCopyNode = currentCopyNode.next
  }

