public class Solution {
    public Node copyRandomList(Node head) {
        if (head == null) {
            return null;
        }

        Node current = head;
        Node newHead = null;
        Node newCurrent = null;

        // Create new nodes with the same values as the original list.
        Node originalNode = head;
        Node dummyHead = new Node(0);
        newCurrent = dummyHead;
        while (originalNode != null) {
            Node newNode = new Node(originalNode.val);
            newCurrent.next = newNode;
            newCurrent = newNode;
            originalNode = originalNode.next;
        }
        newHead = dummyHead.next;

        //Reset pointers for the next iteration
        current = head;
        newCurrent = newHead;

        //Create an array to store all of the original nodes
        Node[] originalNodeArray = new Node[1000];
        Node originalNodeIterator = head;
        int originalNodeArrayIndex = 0;

        //Store nodes in original array
        while (originalNodeIterator != null) {
            originalNodeArray[originalNodeArrayIndex] = originalNodeIterator;
            originalNodeArrayIndex++;
            originalNodeIterator = originalNodeIterator.next;
        }

        //Create an array to store all of the copied nodes
        Node[] copiedNodeArray = new Node[1000];
        Node copiedNodeIterator = newHead;
        int copiedNodeArrayIndex = 0;

        //Store nodes in copied array
        while (copiedNodeIterator != null) {
            copiedNodeArray[copiedNodeArrayIndex] = copiedNodeIterator;
            copiedNodeArrayIndex++;
            copiedNodeIterator = copiedNodeIterator.next;
        }

        // Reset pointers.
        current = head;
        newCurrent = newHead;

        // Iterate through the original list and copy the random pointers.
        while (current != null) {
            if (current.random != null) {
                //Find the index of the original list's random node
                int randomIndex = -1;
                for (int i = 0; i < originalNodeArrayIndex; i++) {
                    if (originalNodeArray[i] == current.random) {
                        randomIndex = i;
                        break;
                    }
                }

                //Set the copied lists random to the node at the same index
                newCurrent.random = copiedNodeArray[randomIndex];
            } else {
                newCurrent.random = null;
            }
            current = current.next;
            newCurrent = newCurrent.next;
        }

        return newHead;
    }
}

