fn copy_list_with_random_pointer(head: Option<Box<Node>>) -> Option<Box<Node>> {
	if head.is_none() {
		return None;
	}

	let mut original_node = head;
	let mut cloned_nodes: HashMap<*const Node, *mut Node> = HashMap::new();
	let mut dummy_head = Box::new(Node { val: 0, next: None, random: None });
	let mut current_cloned_node = &mut dummy_head;

	// Create new nodes with copied values.
	while let Some(node) = original_node {
		let new_node = Box::new(Node { val: node.val, next: None, random: None });
		let new_node_ptr = Box::into_raw(new_node);
		cloned_nodes.insert(&**node as *const Node, new_node_ptr);

		current_cloned_node.next = Some(unsafe { Box::from_raw(new_node_ptr) });
		current_cloned_node = current_cloned_node.next.as_mut().unwrap();
		original_node = node.next;
	}

	original_node = head;
	let mut cloned_head = dummy_head.next;

	// Assign random pointers to the cloned nodes.
	while let Some(node) = original_node {
		let cloned_node_ptr = cloned_nodes.get(&(&**node as *const Node)).unwrap();
		let cloned_node = unsafe { &mut **cloned_node_ptr };

		if let Some(random_node) = &node.random {
			// Need to check for random nodes
			let random_node_ptr = cloned_nodes.get(&(&**random_node as *const Node)).unwrap();
			cloned_node.random = Some(unsafe { Box::from_raw(*random_node_ptr) });
			unsafe {Box::leak(cloned_node.random.take().unwrap());}
